def bad_intersections(V,F,eps=1e-8, verbose=False):
    bad=[]
    for i,j in itertools.combinations(range(len(F)),2):
        pts=tri_tri_intersections(V,F[i],F[j],eps)
        if not pts: continue
        shared=set(map(int,F[i])).intersection(map(int,F[j]))
        # allowed set: if shared edge, segment between shared vertices; if shared vertex, that point; if none, empty.
        for rec in pts:
            point=rec[3][0]
            allowed=False
            if len(shared)>=2:
                sh=list(shared)[:2]
                p=V[sh[0]]; q=V[sh[1]]
                # point on segment p-q
                if np.linalg.norm(np.cross(q-p, point-p)) < 1e-6 and np.dot(point-p, point-q) <= 1e-6:
                    allowed=True
            elif len(shared)==1:
                p=V[list(shared)[0]]
                if np.linalg.norm(point-p)<1e-6:
                    allowed=True
            if not allowed:
                bad.append((i,j,shared,point,rec))
                if verbose: print('bad',i,j,shared,point)
                break
    return bad

