def make_norm(eps=0.01):
    A=[np.array([0.,0.,0.]), np.array([1.,0.,0.]), np.array([0.,1.,0.])]
    B=[np.array([0.5,0,eps]), np.array([0.5-eps,0.5,-2*eps]), np.array([eps,0.5,0.])]
    F=np.array([[0,3,2],[3,1,2],[1,4,0],[4,2,0],[2,5,1],[5,0,1]])
    return np.array(A+B),F
